export const name = "repo";
export const version = "0.1.0";
export const description = "";

export function getIdentity() {
  return { name, version, description };
}

export function slugify(input) {
  const s = ensureString(input);
  if (!s) return "";
  // Normalize and remove diacritics
  const normalized = s.normalize("NFKD").replace(/[\u0300-\u036f]/g, "");
  // Remove invalid chars, allow letters and numbers, convert spaces/underscores to hyphens
  const cleaned = normalized
    .toLowerCase()
    .replace(/[^\p{L}\p{N}\s-]+/gu, "")
    .trim()
    .replace(/[\s_]+/g, "-")
    .replace(/-+/g, "-")
    .replace(/^-+|-+$/g, "");
  return cleaned;
}

export function truncate(input, maxLength = 0, suffix = "…") {
  const s = ensureString(input);
  if (!s) return "";
  if (!maxLength || s.length <= maxLength) return s;
  const suff = ensureString(suffix || "");
  if (maxLength <= 0) return "";
  if (maxLength <= suff.length) return suff.slice(0, maxLength);
  const maxContent = maxLength - suff.length;
  // Try not to break mid-word
  const part = s.slice(0, maxContent + 1);
  const lastSpace = part.lastIndexOf(" ");
  if (lastSpace > 0) {
    return s.slice(0, lastSpace) + suff;
  }
  // No space found; hard cut
  return s.slice(0, maxContent) + suff;
}

export function camelCase(input) {
  const s = ensureString(input);
  if (!s) return "";
  const words = s
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^\p{L}\p{N}]+/gu, " ")
    .trim()
    .split(/\s+/);
  return words
    .map((w, i) => (i === 0 ? w.toLowerCase() : w.charAt(0).toUpperCase() + w.slice(1).toLowerCase()))
    .join("");
}

export function kebabCase(input) {
  const s = ensureString(input);
  if (!s) return "";
  return s
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^\p{L}\p{N}\s-]+/gu, "")
    .trim()
    .toLowerCase()
    .replace(/[\s_]+/g, "-")
    .replace(/-+/g, "-")
    .replace(/^-+|-+$/g, "");
}

export function titleCase(input) {
  const s = ensureString(input);
  if (!s) return "";
  return s
    .normalize("NFKD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/[^\p{L}\p{N}'`]+/gu, " ")
    .trim()
    .split(/\s+/)
    .map((w) => (w ? w.charAt(0).toUpperCase() + w.slice(1).toLowerCase() : ""))
    .join(" ");
}

export function wordWrap(input, width = 80) {
  const s = ensureString(input);
  if (!s) return "";
  if (!width || width <= 0) return s;
  const words = s.split(/\s+/);
  const lines = [];
  let current = "";
  for (const word of words) {
    if (!current) {
      if (word.length > width) {
        // place long word on its own line
        lines.push(word);
      } else {
        current = word;
      }
    } else {
      if (current.length + 1 + word.length <= width) {
        current = current + " " + word;
      } else {
        lines.push(current);
        if (word.length > width) {
          lines.push(word);
          current = "";
        } else {
          current = word;
        }
      }
    }
  }
  if (current) lines.push(current);
  return lines.join("\n");
}

export function stripHtml(input) {
  let s = ensureString(input);
  if (!s) return "";
  // Remove scripts/styles
  s = s.replace(/<script[\s\S]*?<\/script>/gi, "").replace(/<style[\s\S]*?<\/style>/gi, "");
  // Remove tags
  s = s.replace(/<[^>]+>/g, "");
  // Decode common named entities
  const entities = { amp: "&", lt: "<", gt: ">", quot: '"', apos: "'", nbsp: " " };
  s = s.replace(/&([a-zA-Z]+);/g, (m, name) => entities[name.toLowerCase()] ?? m);
  // Decode numeric entities
  s = s.replace(/&#(\d+);?/g, (m, n) => String.fromCharCode(parseInt(n, 10)));
  s = s.replace(/&#x([0-9a-fA-F]+);?/g, (m, n) => String.fromCharCode(parseInt(n, 16)));
  return s;
}

export function escapeRegex(input) {
  const s = ensureString(input);
  if (!s) return "";
  return s.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
}

export function pluralize(input) {
  const s = ensureString(input);
  if (!s) return "";
  // preserve original casing by operating on lower-case but apply replacements to original
  const lower = s.toLowerCase();
  if (/(s|x|z|ch|sh)$/.test(lower)) return s + "es";
  if (/[^aeiou]y$/.test(lower)) return s.slice(0, -1) + "ies";
  if (/(?:fe|f)$/.test(lower)) {
    if (lower.endsWith("fe")) return s.slice(0, -2) + "ves";
    return s.slice(0, -1) + "ves";
  }
  return s + "s";
}

export function levenshtein(a, b) {
  const s = ensureString(a);
  const t = ensureString(b);
  const sa = Array.from(s);
  const tb = Array.from(t);
  const n = sa.length;
  const m = tb.length;
  if (n === 0) return m;
  if (m === 0) return n;
  const v0 = new Array(m + 1);
  const v1 = new Array(m + 1);
  for (let j = 0; j <= m; j++) v0[j] = j;
  for (let i = 0; i < n; i++) {
    v1[0] = i + 1;
    for (let j = 0; j < m; j++) {
      const cost = sa[i] === tb[j] ? 0 : 1;
      v1[j + 1] = Math.min(v1[j] + 1, v0[j + 1] + 1, v0[j] + cost);
    }
    for (let j = 0; j <= m; j++) v0[j] = v1[j];
  }
  return v1[m];
}
